from typing import List

def solve(nums: List[int]) -> bool:
    n = len(nums)
    if n < 5:
        return False

    # Precompute left increasing and right increasing arrays
    left_inc = [False] * n
    left_inc[0] = True
    for i in range(1, n):
        if nums[i] > nums[i-1]:
            left_inc[i] = left_inc[i-1]
        else:
            left_inc[i] = False

    right_inc = [False] * n
    right_inc[-1] = True
    for i in range(n-2, -1, -1):
        if nums[i] < nums[i+1]:
            right_inc[i] = right_inc[i+1]
        else:
            right_inc[i] = False

    # Check for possible p and q
    for p in range(1, n-3):
        if not left_inc[p]:
            continue
        for q in range(p+2, n-1):
            # Check if nums[p..q] is strictly decreasing
            valid = True
            for i in range(p, q):
                if nums[i] <= nums[i+1]:
                    valid = False
                    break
            if valid and right_inc[q]:
                return True
    return False
